    &XMLWhenReportLoading;
    &XMLWhenReportClosing;




      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function load$GridReport$(g) {
  g.add_commandEvent(on$GridReport$ExecuteCommand);
  g.add_onRender(on$GridReport$Render);
}
function dispose$GridReport$(g) {try {
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex){}
  g.remove_onRender(on$GridReport$Render);} catch (ex) {}
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = e.object, result = e.type.Result;
  switch (action) {
    case 'Graph':
      if(f._activeRow == -1) return;
      f.showForm('rptExpensesAggregationReportPivotGraph');
      break;
    default:
      break;
  }
}
function on$GridReport$Render(sender, eventArgs) {
  var name = 'xDetail', g = eventArgs.grid, index = g._getColumnOrder(name), field = g._fields[index - 1];
  var header = $get(g._id + '_HeaderText_' + name), caption = $get('idf_detail'), title = header.title;

  header.title = $func.replace(title, field.HeaderText, g._pivotFieldHeaderText);
  caption.innerHTML = g._pivotFieldHeaderText;
  g._externalHeaderFields = [];
  Array.add(g._externalHeaderFields, {Index: field.Index, Header: g._pivotFieldHeaderText});
  g._setHeaderItemText(index, g._pivotFieldHeaderText);
}
/* </flatten> */



  &CSSGraphReport;
